/**
 * Unit tests for prompt/worktree-advisory-consumer (#1794 PR-2)
 */

import { describe, it, expect, beforeEach, afterEach } from 'vitest';
import { mkdtempSync, rmSync, writeFileSync, mkdirSync, existsSync } from 'node:fs';
import { join } from 'node:path';
import { tmpdir } from 'node:os';
import { worktreeAdvisoryConsumer } from '../prompt/worktree-advisory-consumer.js';
import { writeWorktreeAdvisory } from '../lib/worktree-advisory.js';
import { NOOP_CTX } from '../lib/context.js';
import type { HookInput } from '../types.js';

describe('worktree-advisory-consumer (#1794 PR-2)', () => {
  let tmp: string;

  beforeEach(() => {
    tmp = mkdtempSync(join(tmpdir(), 'wt-consumer-'));
  });

  afterEach(() => {
    try { rmSync(tmp, { recursive: true, force: true }); } catch { /* best-effort */ }
  });

  const inputFor = (projectDir: string): HookInput => ({
    hook_event: 'UserPromptSubmit',
    tool_name: '',
    session_id: 'test-session-pr2',
    tool_input: {},
    prompt: 'anything',
    project_dir: projectDir,
  });

  it('returns silent success when no advisories are pending', () => {
    const result = worktreeAdvisoryConsumer(inputFor(tmp), NOOP_CTX);
    expect(result).toEqual({ continue: true, suppressOutput: true });
  });

  it('returns silent success when project_dir is missing', () => {
    const result = worktreeAdvisoryConsumer(
      { hook_event: 'UserPromptSubmit', tool_name: '', session_id: 's', tool_input: {} },
      NOOP_CTX,
    );
    expect(result).toEqual({ continue: true, suppressOutput: true });
  });

  it('injects pending advisory as additionalContext and consumes it', () => {
    writeWorktreeAdvisory('Monorepo — set sparsePaths', 'feat-x', tmp);
    const result = worktreeAdvisoryConsumer(inputFor(tmp), NOOP_CTX);
    const ctx = result.hookSpecificOutput?.additionalContext as string;
    expect(ctx).toContain('Monorepo — set sparsePaths');
    expect(result.hookSpecificOutput?.hookEventName).toBe('UserPromptSubmit');
    // Second call: state is clean
    const next = worktreeAdvisoryConsumer(inputFor(tmp), NOOP_CTX);
    expect(next).toEqual({ continue: true, suppressOutput: true });
  });

  it('joins multiple pending advisories with separator', () => {
    writeWorktreeAdvisory('advisory A', 'a', tmp);
    writeWorktreeAdvisory('advisory B', 'b', tmp);
    const result = worktreeAdvisoryConsumer(inputFor(tmp), NOOP_CTX);
    const ctx = result.hookSpecificOutput?.additionalContext as string;
    expect(ctx).toContain('advisory A');
    expect(ctx).toContain('advisory B');
    expect(ctx).toContain('---');
  });

  it('falls back to ctx.projectDir when input.project_dir is absent', () => {
    writeWorktreeAdvisory('via ctx.projectDir', 'wt', tmp);
    const input: HookInput = {
      hook_event: 'UserPromptSubmit',
      tool_name: '',
      session_id: 's',
      tool_input: {},
    };
    const ctxWithProjectDir = { ...NOOP_CTX, projectDir: tmp };
    const result = worktreeAdvisoryConsumer(input, ctxWithProjectDir);
    const ctx = result.hookSpecificOutput?.additionalContext as string;
    expect(ctx).toContain('via ctx.projectDir');
  });

  it('does not touch non-advisory files in .claude/state/', () => {
    writeWorktreeAdvisory('the advisory', 'wt', tmp);
    const stateDir = join(tmp, '.claude', 'state');
    mkdirSync(stateDir, { recursive: true });
    writeFileSync(join(stateDir, 'goal-history.jsonl'), '{"goal":"keep this"}\n');
    worktreeAdvisoryConsumer(inputFor(tmp), NOOP_CTX);
    // Advisory deleted; goal-history preserved
    expect(existsSync(join(stateDir, 'worktree-advisory-wt.md'))).toBe(false);
    expect(existsSync(join(stateDir, 'goal-history.jsonl'))).toBe(true);
  });

  it('does not stamp UserPromptSubmit envelope when no advisory pending (silent OK shape)', () => {
    const result = worktreeAdvisoryConsumer(inputFor(tmp), NOOP_CTX);
    expect(result.hookSpecificOutput).toBeUndefined();
  });

  it('hook never throws on malformed input', () => {
    // @ts-expect-error — testing defensive behavior
    expect(() => worktreeAdvisoryConsumer({}, NOOP_CTX)).not.toThrow();
    // @ts-expect-error — testing defensive behavior
    expect(() => worktreeAdvisoryConsumer(null, NOOP_CTX)).not.toThrow();
  });
});
